import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;

public class BankTransactionProcessor {

    private Connection connection;

    public BankTransactionProcessor(Connection connection) {
        this.connection = connection;
    }

    public void processTransaction(int accountId, double transactionAmount) {
        synchronized (this) {
            try {
                connection.setAutoCommit(false);

                double currentBalance = getAccountBalance(accountId);
                if (validateTransaction(currentBalance, transactionAmount)) {
                    updateAccountBalance(accountId, currentBalance + transactionAmount);
                }

                connection.commit();
            } catch (SQLException e) {
                try {
                    connection.rollback();
                } catch (SQLException rollbackEx) {
                    rollbackEx.printStackTrace();
                }
                e.printStackTrace();
            } finally {
                try {
                    connection.setAutoCommit(true);
                } catch (SQLException e) {
                    e.printStackTrace();
                }
            }
        }
    }

    private double getAccountBalance(int accountId) throws SQLException {
        String query = "SELECT balance FROM accounts WHERE account_id = ?";
        try (PreparedStatement stmt = connection.prepareStatement(query)) {
            stmt.setInt(1, accountId);
            try (ResultSet rs = stmt.executeQuery()) {
                if (rs.next()) {
                    return rs.getDouble("balance");
                } else {
                    throw new SQLException("Account not found");
                }
            }
        }
    }

    private boolean validateTransaction(double currentBalance, double transactionAmount) {
        return currentBalance + transactionAmount >= 0;
    }

    private void updateAccountBalance(int accountId, double newBalance) throws SQLException {
        String update = "UPDATE accounts SET balance = ? WHERE account_id = ?";
        try (PreparedStatement stmt = connection.prepareStatement(update)) {
            stmt.setDouble(1, newBalance);
            stmt.setInt(2, accountId);
            stmt.executeUpdate();
        }
    }
}